      if (dx === 0 && dy === 0) continue;
      if (livingSet.has(key(x + dx, y + dy))) count++;
    }
  }
  return count;
};

export const nextGeneration = (livingCells: Cell[]): Cell[] => {
  const livingSet = new Set(livingCells.map(([x, y]) => key(x, y)));

  // Candidates = living cells + their dead neighbors
  const candidates = new Set<string>();
  for (const [x, y] of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        candidates.add(key(x + dx, y + dy));
      }
    }
  }

  const next: Cell[] = [];
  for (const k of candidates) {
    const [x, y] = parseKey(k);
    const n = countLivingNeighbors(livingSet, x, y);
    const alive = livingSet.has(k);
    if (alive && (n === 2 || n === 3)) next.push([x, y]);
    else if (!alive && n === 3) next.push([x, y]);
  }
  return next;
};

